using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using ResearchAgent.Tools;

var builder = Host.CreateApplicationBuilder(args);

var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable or AI:ApiKey in configuration.");

var modelId = builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(b => b
    .UseOpenAIChatClient(modelId, new OpenAI.OpenAIClient(apiKey)));

builder.Services.AddSingleton<NoteStore>();
builder.Services.AddHttpClient("WebSearch");

var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var noteStore = host.Services.GetRequiredService<NoteStore>();
var httpFactory = host.Services.GetRequiredService<IHttpClientFactory>();

var searchTool = new WebSearchTool(httpFactory);
var notesTool = new NotesTool(noteStore);

var tools = new AIToolCollection
{
    AIFunctionFactory.Create(searchTool.SearchWebAsync),
    AIFunctionFactory.Create(notesTool.AddNote),
    AIFunctionFactory.Create(notesTool.GetNotes),
    AIFunctionFactory.Create(notesTool.ClearNotes),
};

Console.WriteLine("=== Research Agent ===");
Console.WriteLine("Enter a topic to research (or 'quit' to exit):");
Console.Write("> ");

while (Console.ReadLine() is { } input && !input.Equals("quit", StringComparison.OrdinalIgnoreCase))
{
    if (string.IsNullOrWhiteSpace(input))
    {
        Console.Write("> ");
        continue;
    }

    noteStore.Clear();

    var systemPrompt = """
        You are a research agent. Your job is to research a topic thoroughly using the available tools.

        Follow this workflow:
        1. Search the web for information about the topic using multiple queries.
        2. Take notes on the key findings using the AddNote tool.
        3. After gathering enough information, retrieve your notes and provide a comprehensive summary.

        Always cite your sources. Be thorough but concise in your final summary.
        """;

    var messages = new List<ChatMessage>
    {
        new(ChatRole.System, systemPrompt),
        new(ChatRole.User, $"Research the following topic and provide a summary: {input}"),
    };

    var options = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 4096,
        Tools = tools,
        ToolMode = ChatToolMode.Auto,
    };

    Console.WriteLine($"\nResearching: {input}\n");

    const int maxIterations = 15;
    int iteration = 0;

    while (iteration++ < maxIterations)
    {
        var response = await chatClient.GetResponseAsync(messages, options);

        messages.AddMessages(response);

        // Check if the model made tool calls
        bool hasToolCalls = response.Messages
            .Any(m => m.Contents.OfType<FunctionCallContent>().Any());

        if (!hasToolCalls)
        {
            // Final response — print it
            var finalText = response.Messages
                .SelectMany(m => m.Contents.OfType<TextContent>())
                .LastOrDefault()?.Text;

            if (!string.IsNullOrEmpty(finalText))
            {
                Console.WriteLine("--- Research Summary ---\n");
                Console.WriteLine(finalText);
                Console.WriteLine("\n--- End of Summary ---");
            }
            break;
        }

        // Log tool calls for observability
        var toolCalls = response.Messages
            .SelectMany(m => m.Contents.OfType<FunctionCallContent>());
        foreach (var call in toolCalls)
        {
            Console.WriteLine($"  [Tool] {call.Name}");
        }
    }

    if (iteration > maxIterations)
    {
        Console.WriteLine("\n[Agent reached maximum iterations]");
    }

    Console.WriteLine($"\nNotes collected: {noteStore.Count}");
    Console.Write("\n> ");
}

Console.WriteLine("Goodbye!");

