using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using System.Web;

namespace ResearchAgent.Tools;

public sealed class WebSearchTool(IHttpClientFactory httpClientFactory)
{
    [Description("Searches the web for information about a query. Returns a list of results with titles, snippets, and URLs.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query to look up on the web")] string query,
        [Description("Maximum number of results to return (default: 5)")] int maxResults = 5)
    {
        using var client = httpClientFactory.CreateClient("WebSearch");
        client.DefaultRequestHeaders.UserAgent.ParseAdd(
            "ResearchAgent/1.0 (compatible; research-bot)");

        try
        {
            // Use DuckDuckGo HTML search as a free web search source
            var encodedQuery = HttpUtility.UrlEncode(query);
            var url = $"https://html.duckduckgo.com/html/?q={encodedQuery}";

            var html = await client.GetStringAsync(url);

            var results = ParseSearchResults(html, maxResults);

            if (results.Count == 0)
            {
                return $"No results found for: {query}";
            }

            var output = results.Select((r, i) =>
                $"[{i + 1}] {r.Title}\n    URL: {r.Url}\n    Snippet: {r.Snippet}");

            return $"Search results for \"{query}\":\n\n{string.Join("\n\n", output)}";
        }
        catch (HttpRequestException ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
