+            }
+
+            var output = results.Select((r, i) =>
+                $"[{i + 1}] {r.Title}\n    URL: {r.Url}\n    Snippet: {r.Snippet}");
+
+            return $"Search results for \"{query}\":\n\n{string.Join("\n\n", output)}";
+        }
+        catch (HttpRequestException ex)
+        {
+            return $"Search failed: {ex.Message}. Try a different query.";
+        }
+    }
