+    {
+        var results = new List<SearchResult>();
+
+        // Parse DuckDuckGo HTML results
+        var resultBlocks = html.Split("class=\"result__a\"", StringSplitOptions.RemoveEmptyEntries);
+
+        for (int i = 1; i < resultBlocks.Length && results.Count < maxResults; i++)
+        {
+            var block = resultBlocks[i];
+
+            var title = ExtractBetween(block, ">", "</a>")?.Trim();
+            var snippet = ExtractSnippet(block);
+            var url = ExtractUrl(block);
+
+            if (!string.IsNullOrEmpty(title))
+            {
+                results.Add(new SearchResult
+                {
+                    Title = StripHtml(title),
+                    Snippet = StripHtml(snippet ?? "No snippet available"),
+                    Url = url ?? "URL not available",
+                });
+            }
+        }
+
+        return results;
+    }
