using System.ComponentModel;

namespace ResearchAgent.Tools;

public sealed class NotesTool(NoteStore store)
{
    [Description("Adds a research note with a category and content. Use this to record key findings during research.")]
    public string AddNote(
        [Description("Category for the note (e.g., 'definition', 'fact', 'source', 'opinion')")] string category,
        [Description("The content of the note")] string content,
        [Description("Optional source URL or reference")] string? source = null)
    {
        store.Add(category, content, source);
        return $"Note added to '{category}' (total notes: {store.Count})";
    }

    [Description("Retrieves all research notes collected so far, optionally filtered by category.")]
    public string GetNotes(
        [Description("Optional category to filter notes by. Leave empty to get all notes.")] string? category = null)
    {
        var notes = store.GetNotes(category);

        if (notes.Count == 0)
        {
            return category is null
                ? "No notes have been collected yet."
                : $"No notes found in category '{category}'.";
        }

        var formatted = notes.Select((n, i) =>
        {
            var sourceInfo = string.IsNullOrEmpty(n.Source) ? "" : $"\n    Source: {n.Source}";
            return $"[{i + 1}] [{n.Category}] {n.Content}{sourceInfo}";
        });

        return $"Research notes ({notes.Count} total):\n\n{string.Join("\n\n", formatted)}";
    }

    [Description("Clears all research notes. Use when starting research on a new topic.")]
    public string ClearNotes()
    {
        var count = store.Count;
        store.Clear();
        return $"Cleared {count} notes.";
    }
}

