namespace ResearchAgent.Tools;

public sealed class NoteStore
{
    private readonly List<Note> _notes = [];
    private readonly Lock _lock = new();

    public int Count
    {
        get { lock (_lock) { return _notes.Count; } }
    }

    public void Add(string category, string content, string? source)
    {
        lock (_lock)
        {
            _notes.Add(new Note
            {
                Category = category,
                Content = content,
                Source = source,
                Timestamp = DateTimeOffset.UtcNow,
            });
        }
    }

    public List<Note> GetNotes(string? category = null)
    {
        lock (_lock)
        {
            return category is null
                ? [.. _notes]
                : _notes.Where(n => n.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
        }
    }

    public void Clear()
    {
        lock (_lock) { _notes.Clear(); }
    }
}

public sealed class Note
{
    public required string Category { get; init; }
    public required string Content { get; init; }
    public string? Source { get; init; }
    public DateTimeOffset Timestamp { get; init; }
}

